              vm_offset_t pb = (vm_offset_t)pMemFreeBSD->Core.pv + ptoa(iPage);

@@ -375,7 +381,7 @@
          }

          case RTR0MEMOBJTYPE_MAPPING:
-@@ -857,11 +921,15 @@
